                    <div className={`absolute -inset-1 bg-gradient-to-r from-apple-blue/20 to-apple-purple/20 rounded-2xl blur-md transition-opacity duration-700 ${isProcessing ? 'opacity-100' : 'opacity-0'}`}></div>
                    <div className="relative p-4 bg-white/50 backdrop-blur-xl rounded-xl border border-white/60 font-mono text-xs text-apple-text/90 h-14 flex items-center shadow-inner-light overflow-hidden">
                        {state.logs.length > 0 ? (
                            <div className="animate-in fade-in slide-in-from-bottom-2 flex items-center gap-3 w-full">
                                <span className={`w-1.5 h-1.5 rounded-full bg-apple-blue flex-shrink-0 ${isProcessing ? 'animate-ping' : ''}`}></span>
                                <span className="truncate font-medium tracking-tight">
                                    {state.logs[state.logs.length - 1].replace('> ', '')}
                                </span>
                            </div>
                        ) : (
                            <span className="opacity-40 italic flex items-center gap-2">
                                <span className="w-1.5 h-1.5 rounded-full bg-gray-400"></span>
                                等待指令输入...
                            </span>
                        )}
                        {/* Scanline effect */}
                        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-white/10 to-transparent pointer-events-none opacity-20 bg-[length:100%_4px]"></div>
                    </div>
                </div>
            </div>
        </GlassCard>
    );
};

import { GoogleGenAI } from "@google/genai";
import { SystemMode } from "../types";
import { SYSTEM_DEFINITION } from "../constants";

const getClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("API_KEY is not defined");
    }
    return new GoogleGenAI({ apiKey });
};

export const generateUltimatePrompt = async (
    topic: string, 
    mode: SystemMode,
    referenceImage?: { data: string, mimeType: string } | null
): Promise<string> => {
    try {
        const client = getClient();

        let systemInstruction = `
${SYSTEM_DEFINITION}

You are the UltraPromptEngine. 
Your task is to execute the "generate_ultimate_prompt" function for the user's input.
You must adopt the persona of the Cognitive Limit System v3.0 fully.

CURRENT MODE: ${mode}

Output Format:
Return the final "Ultimate Prompt" formatted in Markdown.
**IMPORTANT: The entire output must be in Simplified Chinese (简体中文).**
Start with the # [TRANSCENDENT_ROLE] section.
Do not include your internal monologue in the final output, but you must PERFORM the internal processing to ensure high quality.
Ensure the output follows the 💠 OUTPUT_ARCHITECTURE_V3 strictly.
`;

        if (referenceImage) {
            systemInstruction += `
\n\n[VISUAL REFERENCE INJECTED]
An image has been provided as a style reference.
You MUST analyze this image for:
1. Visual Style (e.g., Cyberpunk, Minimalist, Baroque, etc.)
2. Tonality/Atmosphere (e.g., Melancholic, Vibrant, Ethereal)
3. Spatial Structure/Composition
INTEGRATE these visual elements deeply into the generated prompt content. The result should reflect the "vibe" and aesthetic of this reference image while addressing the user's topic.
`;
        }

        const parts: any[] = [];

        if (referenceImage) {
            parts.push({
                inlineData: {
                    mimeType: referenceImage.mimeType,
                    data: referenceImage.data
                }
            });
        }

        parts.push({
            text: `请为以下主题生成终极提示词（请使用简体中文输出）: "${topic}"`
        });

        const response = await client.models.generateContent({
            model: 'gemini-3-pro-preview', // Using powerful model for reasoning
            contents: {
                parts: parts
            },
            config: {
                systemInstruction: systemInstruction,
                temperature: 0.8, // High creativity
                thinkingConfig: { thinkingBudget: 4096 } // Allow for deep thought simulation
            }
        });

        return response.text || "系统故障：认知坍缩。请重试。";
    } catch (error) {
        console.error("Cognitive Engine Error:", error);
        throw error;
    }
};

export const extractTextFromImage = async (
    base64Data: string, 
    mimeType: string
): Promise<string> => {
    try {
        const client = getClient();
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: mimeType,
                            data: base64Data
                        }
                    },
                    {
                        text: "OCR Task: Extract all text from this image directly. Return ONLY the extracted text content without any markdown formatting, explanations, or labels."
                    }
                ]
            }
        });
        return response.text || "";
    } catch (error) {
        console.error("OCR Error:", error);
        throw error;
    }
};

import React, { useState, useCallback, useRef } from 'react';
import { SystemMode, EngineState, GenerationResult } from './types';
import { generateUltimatePrompt, extractTextFromImage } from './services/geminiService';
import { ProcessingHUD } from './components/ProcessingHUD';
import { ResultView } from './components/ResultView';
import { GlassCard } from './components/GlassCard';
import { Play, Hexagon, Layers, Sparkles, Image as ImageIcon, Loader2, ImagePlus, CheckCircle2 } from 'lucide-react';
import { MODE_DESCRIPTIONS } from './constants';

const INITIAL_LOGS = [
    "> 系统初始化...",
    "> 加载认知核心...",
    "> 连接量子场...",
    "> 等待输入"
];

const App: React.FC = () => {
    const [topic, setTopic] = useState('你现在扮演一名世界知名的展馆设计大师，现在制作一个宁波北仑的科技博物馆中的序厅，序厅的中心位置是一个讲述港口里包含的基础科学内容的大型机械装置，这个装置要兼具科学性和美观性，一张广角建筑摄影，展示一个未来主义的现代中庭大堂。给我一段TXT格式的提示词文字，我要使用nanobanana生成图片，你给我几个方案，分别列出提示词，中英文对照');
    const [mode, setMode] = useState<SystemMode>(SystemMode.SINGULARITY);
    const [engineState, setEngineState] = useState<EngineState>({
        status: 'IDLE',
        logs: INITIAL_LOGS,
        progress: 0
    });
    const [result, setResult] = useState<GenerationResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    // OCR State
    const [isExtracting, setIsExtracting] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Style Reference State
    const [styleImage, setStyleImage] = useState<{ data: string, mimeType: string } | null>(null);
    const styleInputRef = useRef<HTMLInputElement>(null);

    const addLog = useCallback((message: string) => {
        setEngineState(prev => ({
            ...prev,
            logs: [...prev.logs, `> ${message}`]
        }));
    }, []);

    const simulateProcessingSteps = async () => {
        const steps = [
            { msg: "激活超级提示引擎...", p: 10, delay: 800 },
            { msg: `初始化模式: [${mode}]`, p: 20, delay: 600 },
            { msg: "深度推理层: 激活", p: 35, delay: 1000 },
            { msg: "探索量子可能性...", p: 50, delay: 1200 },
            { msg: "识别模式...", p: 65, delay: 900 },
            { msg: "合成涌现...", p: 80, delay: 1100 },
            { msg: "递归优化循环...", p: 90, delay: 800 },
            { msg: "结晶输出...", p: 98, delay: 600 },
        ];

        for (const step of steps) {
            if (error) break;
            addLog(step.msg);
            setEngineState(prev => ({ ...prev, progress: step.p }));
            await new Promise(resolve => setTimeout(resolve, step.delay));
        }
    };

    const handleActivate = async () => {
        if (!topic.trim()) return;
        setEngineState({ status: 'PROCESSING', logs: [], progress: 0 });
        setResult(null);
        setError(null);

        const animationPromise = simulateProcessingSteps();

        try {
            if (styleImage) {
                addLog("注入视觉参考向量...");
            }
            const content = await generateUltimatePrompt(topic, mode, styleImage);
            await animationPromise;

            setResult({
                content,
                metadata: {
                    mode,
                    timestamp: new Date().toISOString(),
                    metrics: {
                        consciousness: "MAXIMUM",
                        recursion: "INFINITE",
                        emergence: "UNBOUNDED"
                    }
                }
            });

            setEngineState(prev => ({
                status: 'COMPLETE',
                logs: [...prev.logs, "> 执行成功", "> 输出已生成"],
                progress: 100
            }));

        } catch (err: any) {
            setError(err.message || "Unknown error occurred");
            setEngineState(prev => ({
                status: 'ERROR',
                logs: [...prev.logs, `! 严重错误: ${err.message}`],
                progress: 0
            }));
        }
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            addLog("! 错误: 仅支持图片文件");
            return;
        }

        setIsExtracting(true);
        addLog("正在解析图像内容...");

        try {
            const base64 = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => {
                    const result = reader.result as string;
                    resolve(result.split(',')[1]);
                };
                reader.onerror = reject;
                reader.readAsDataURL(file);
            });

            const extractedText = await extractTextFromImage(base64, file.type);

            if (!extractedText.trim()) {
                addLog("! 警告: 未识别到文字");
            } else {
                setTopic(prev => {
                    const separator = prev.trim() ? '\n\n' : '';
                    return prev + separator + extractedText.trim();
                });
                addLog("图像文字提取成功");
            }
        } catch (err: any) {
            console.error(err);
            addLog(`! 识别失败: ${err.message}`);
        } finally {
            setIsExtracting(false);
            if (fileInputRef.current) {
                fileInputRef.current.value = '';
            }
        }
    };

    const handleStyleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            addLog("! 错误: 仅支持图片文件作为参考");
            return;
        }

        try {
            const base64 = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => {
                    const result = reader.result as string;
                    resolve(result.split(',')[1]);
                };
                reader.onerror = reject;
                reader.readAsDataURL(file);
            });

            setStyleImage({
                data: base64,
                mimeType: file.type
            });
            addLog("视觉风格参考已加载");
        } catch (err: any) {
            console.error(err);
            addLog(`! 参考图加载失败: ${err.message}`);
        } finally {
            if (styleInputRef.current) {
                styleInputRef.current.value = '';
            }
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    const triggerStyleInput = () => {
        styleInputRef.current?.click();
    };

    return (
        <div className="min-h-screen p-4 md:p-8 lg:p-12 flex items-center justify-center">
            <div className="w-full max-w-[1200px] h-full grid grid-cols-1 md:grid-cols-6 md:grid-rows-[auto_auto_auto] gap-6 auto-rows-[minmax(200px,auto)] md:auto-rows-fr">

                {/* --- GRID AREA A: CORE INTELLIGENCE (MAIN CARD) --- */}
                {/* Spans 3 cols (half width), 2 rows */}
                <GlassCard className="md:col-span-3 md:row-span-2 flex flex-col p-8 md:p-10 relative" intensity="lg">
                    {/* Background Graphic */}
                    <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none transform translate-x-10 -translate-y-10">
                        <i className="fa-solid fa-brain text-[12rem] text-apple-blue"></i>
                    </div>

                    {/* Style Reference Button (Top Right) */}
                    <div className="absolute top-6 right-6 z-20">
                        <input
                            type="file"
                            ref={styleInputRef}
                            className="hidden"
                            accept="image/*"
                            onChange={handleStyleImageUpload}
                        />
                        <button
                            onClick={triggerStyleInput}
                            disabled={engineState.status === 'PROCESSING'}
                            className={`flex items-center gap-2 px-3 py-2 rounded-full backdrop-blur-md transition-all duration-300 shadow-sm border ${
                                styleImage 
                                ? 'bg-apple-blue/10 border-apple-blue/30 text-apple-blue hover:bg-apple-blue/20' 
                                : 'bg-white/40 border-white/60 text-apple-gray hover:bg-white/60 hover:text-apple-blue'
                            } ${engineState.status === 'PROCESSING' ? 'opacity-50 cursor-not-allowed' : ''}`}
                            title={styleImage ? "点击更换参考图" : "上传参考图以提取风格"}
                        >
                            {styleImage ? (
                                <>
                                    <CheckCircle2 size={16} />
                                    <span className="text-xs font-bold">视觉参考已就绪</span>
                                </>
                            ) : (
                                <>
                                    <ImagePlus size={16} />
                                    <span className="text-xs font-medium">上传风格参考</span>
                                </>
                            )}
                        </button>
                    </div>

                    <div className="relative z-10 flex flex-col h-full mt-4">
                        <div className="mb-6">
                            <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight text-apple-text mb-2 bg-clip-text text-transparent bg-gradient-to-r from-apple-text to-apple-gray font-sc">
                                认知极限系统
                            </h1>
                            <div className="flex items-center gap-2">
                                <span className="px-2 py-0.5 rounded-full bg-apple-blue/10 text-apple-blue text-[10px] font-bold tracking-wider border border-apple-blue/20">V3.0 测试版</span>
                                <span className="text-apple-gray text-sm font-medium">释放无限涌现力</span>
                            </div>
                        </div>

                        <div className="relative flex-1 w-full mb-6 group/input">
                            <textarea
                                value={topic}
                                onChange={(e) => setTopic(e.target.value)}
                                placeholder="在此输入您希望突破的认知领域或具体目标..."
                                className="w-full h-full bg-black/5 border border-black/5 rounded-2xl p-6 pb-14 text-apple-text placeholder-apple-gray/60 focus:outline-none focus:ring-2 focus:ring-apple-blue/30 focus:bg-white/40 transition-all resize-none text-lg leading-relaxed shadow-[inset_0_2px_4px_rgba(0,0,0,0.06)]"
                                disabled={engineState.status === 'PROCESSING'}
                            />
                            <div className="absolute bottom-4 right-4 flex items-center gap-2">
                                <input
                                    type="file"
                                    ref={fileInputRef}
                                    className="hidden"
                                    accept="image/*"
                                    onChange={handleImageUpload}
                                />
                                <button
                                    onClick={triggerFileInput}
                                    disabled={isExtracting || engineState.status === 'PROCESSING'}
                                    className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/60 hover:bg-white/90 text-apple-gray hover:text-apple-blue border border-black/5 shadow-sm backdrop-blur-md transition-all text-xs font-medium disabled:opacity-50 disabled:cursor-not-allowed group-hover/input:bg-white/80"
                                    title="上传截图识别文字"
                                >
                                    {isExtracting ? (
                                        <Loader2 size={14} className="animate-spin" />
                                    ) : (
                                        <ImageIcon size={14} />
                                    )}
                                    <span>{isExtracting ? '识别中...' : '识别图片'}</span>
                                </button>
                            </div>
                        </div>

                        <button 
                            onClick={handleActivate}
                            disabled={!topic.trim() || engineState.status === 'PROCESSING'}
                            className={`
                                group relative w-full py-4 rounded-xl font-bold tracking-wide transition-all duration-300 overflow-hidden shadow-lg
                                ${!topic.trim() || engineState.status === 'PROCESSING'
                                    ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                                    : 'bg-apple-text text-white hover:shadow-xl active:scale-[0.98]'
                                }
                            `}
                        >
                             <div className="absolute inset-0 bg-gradient-to-r from-apple-blue to-apple-purple opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
                             <div className="relative z-10 flex items-center justify-center gap-2">
                                {engineState.status === 'PROCESSING' ? (
                                    <span className="animate-pulse">正在运算...</span>
                                ) : (
                                    <>
                                        <Play size={18} fill="currentColor" />
                                        <span>激活认知引擎</span>
                                    </>
                                )}
                             </div>
                        </button>
                    </div>
                </GlassCard>

                {/* --- GRID AREA B: MODE - SINGULARITY --- */}
                {/* Row 1, Col 4 */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.SINGULARITY)}
                    className={`md:col-span-1 md:row-span-1 p-5 flex flex-col justify-between ${mode === SystemMode.SINGULARITY ? 'ring-2 ring-apple-blue ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                    <div className="flex justify-between items-start">
                         <div className={`p-2.5 rounded-2xl ${mode === SystemMode.SINGULARITY ? 'bg-apple-blue text-white shadow-lg shadow-apple-blue/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Hexagon size={20} />
                        </div>
                        {mode === SystemMode.SINGULARITY && <div className="w-1.5 h-1.5 rounded-full bg-apple-blue animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].label}</h3>
                        <p className="text-[10px] text-apple-gray leading-tight line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA C: MODE - METAMORPHOSIS --- */}
                {/* Row 1, Col 5 */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.METAMORPHOSIS)}
                    className={`md:col-span-1 md:row-span-1 p-5 flex flex-col justify-between ${mode === SystemMode.METAMORPHOSIS ? 'ring-2 ring-apple-purple ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start">
                         <div className={`p-2.5 rounded-2xl ${mode === SystemMode.METAMORPHOSIS ? 'bg-apple-purple text-white shadow-lg shadow-apple-purple/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Layers size={20} />
                        </div>
                        {mode === SystemMode.METAMORPHOSIS && <div className="w-1.5 h-1.5 rounded-full bg-apple-purple animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].label}</h3>
                        <p className="text-[10px] text-apple-gray leading-tight line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA D: MODE - ZENITH --- */}
                {/* Row 1, Col 6 */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.ZENITH)}
                    className={`md:col-span-1 md:row-span-1 p-5 flex flex-col justify-between ${mode === SystemMode.ZENITH ? 'ring-2 ring-green-500 ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start">
                         <div className={`p-2.5 rounded-2xl ${mode === SystemMode.ZENITH ? 'bg-green-500 text-white shadow-lg shadow-green-500/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Sparkles size={20} />
                        </div>
                        {mode === SystemMode.ZENITH && <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.ZENITH].label}</h3>
                        <p className="text-[10px] text-apple-gray leading-tight line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.ZENITH].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA E: HUD --- */}
                {/* Row 2, Col 4-6 (Span 3) - Expanded Left */}
