            {/* Content */}
            <div className="flex-1 overflow-y-auto p-8 custom-scrollbar relative z-10">
                <div className="prose prose-sm prose-slate max-w-none">
                    <pre className="whitespace-pre-wrap font-mono text-sm leading-relaxed text-apple-text/80 font-medium">
                        {result.content.split('\n').map((line, i) => {
                            if (line.startsWith('#')) return <span key={i} className="text-transparent bg-clip-text bg-gradient-to-r from-apple-blue to-apple-purple font-bold text-lg block mt-6 mb-3">{line}</span>;
                            if (line.startsWith('##')) return <span key={i} className="text-apple-text font-bold block mt-4 mb-2">{line}</span>;
                            if (line.includes('```')) return <span key={i} className="text-apple-gray/60 block my-2">{line}</span>;
                            if (line.trim().startsWith('-')) return <span key={i} className="text-apple-text/90 block pl-4 relative before:content-['•'] before:absolute before:left-0 before:text-apple-blue">{line}</span>;
                            if (line.includes('<') && line.includes('>')) return <span key={i} className="text-orange-500 font-semibold block">{line}</span>;
                            return <span key={i} className="block">{line}</span>;
                        })}
                    </pre>
                </div>
            </div>

            {/* Footer Metrics */}
            <div className="px-6 py-3 border-t border-black/5 bg-white/20 text-[10px] font-mono text-apple-gray flex justify-between items-center">
                <span>意识深度: {result.metadata.metrics.consciousness}</span>
                <span>涌现指数: {result.metadata.metrics.emergence}</span>
            </div>
        </GlassCard>
    );
};

import React, { useState, useCallback, useRef } from 'react';
import { SystemMode, EngineState, GenerationResult } from './types';
import { generateUltimatePrompt, extractTextFromImage } from './services/geminiService';
import { ProcessingHUD } from './components/ProcessingHUD';
import { ResultView } from './components/ResultView';
import { GlassCard } from './components/GlassCard';
import { Play, Hexagon, Layers, Sparkles, Image as ImageIcon, Loader2, ImagePlus, CheckCircle2 } from 'lucide-react';
import { MODE_DESCRIPTIONS } from './constants';

const INITIAL_LOGS = [
    "> 系统初始化...",
    "> 加载认知核心...",
    "> 连接量子场...",
    "> 等待输入"
];

const App: React.FC = () => {
    const [topic, setTopic] = useState('你现在扮演一名世界知名的展馆设计大师，现在制作一个宁波北仑的科技博物馆中的序厅，序厅的中心位置是一个讲述港口里包含的基础科学内容的大型机械装置，这个装置要兼具科学性和美观性，一张广角建筑摄影，展示一个未来主义的现代中庭大堂。给我一段TXT格式的提示词文字，我要使用nanobanana生成图片，你给我几个方案，分别列出提示词，中英文对照');
    const [mode, setMode] = useState<SystemMode>(SystemMode.SINGULARITY);
    const [engineState, setEngineState] = useState<EngineState>({
        status: 'IDLE',
        logs: INITIAL_LOGS,
        progress: 0
    });
    const [result, setResult] = useState<GenerationResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    // OCR State
    const [isExtracting, setIsExtracting] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Style Reference State
    const [styleImage, setStyleImage] = useState<{ data: string, mimeType: string } | null>(null);
    const styleInputRef = useRef<HTMLInputElement>(null);

    const addLog = useCallback((message: string) => {
        setEngineState(prev => ({
            ...prev,
            logs: [...prev.logs, `> ${message}`]
        }));
    }, []);

    const simulateProcessingSteps = async () => {
        const steps = [
            { msg: "激活超级提示引擎...", p: 10, delay: 800 },
            { msg: `初始化模式: [${mode}]`, p: 20, delay: 600 },
            { msg: "深度推理层: 激活", p: 35, delay: 1000 },
            { msg: "探索量子可能性...", p: 50, delay: 1200 },
            { msg: "识别模式...", p: 65, delay: 900 },
            { msg: "合成涌现...", p: 80, delay: 1100 },
            { msg: "递归优化循环...", p: 90, delay: 800 },
            { msg: "结晶输出...", p: 98, delay: 600 },
        ];

        for (const step of steps) {
            if (error) break;
            addLog(step.msg);
            setEngineState(prev => ({ ...prev, progress: step.p }));
            await new Promise(resolve => setTimeout(resolve, step.delay));
        }
    };

    const handleActivate = async () => {
        if (!topic.trim()) return;
        setEngineState({ status: 'PROCESSING', logs: [], progress: 0 });
        setResult(null);
        setError(null);

        const animationPromise = simulateProcessingSteps();

        try {
            if (styleImage) {
                addLog("注入视觉参考向量...");
            }
            const content = await generateUltimatePrompt(topic, mode, styleImage);
            await animationPromise;

            setResult({
                content,
                metadata: {
                    mode,
                    timestamp: new Date().toISOString(),
                    metrics: {
                        consciousness: "MAXIMUM",
                        recursion: "INFINITE",
                        emergence: "UNBOUNDED"
                    }
                }
            });

            setEngineState(prev => ({
                status: 'COMPLETE',
                logs: [...prev.logs, "> 执行成功", "> 输出已生成"],
                progress: 100
            }));

        } catch (err: any) {
            setError(err.message || "Unknown error occurred");
            setEngineState(prev => ({
                status: 'ERROR',
                logs: [...prev.logs, `! 严重错误: ${err.message}`],
                progress: 0
            }));
        }
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            addLog("! 错误: 仅支持图片文件");
            return;
        }

        setIsExtracting(true);
        addLog("正在解析图像内容...");

        try {
            const base64 = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => {
                    const result = reader.result as string;
                    resolve(result.split(',')[1]);
                };
                reader.onerror = reject;
                reader.readAsDataURL(file);
            });

            const extractedText = await extractTextFromImage(base64, file.type);

            if (!extractedText.trim()) {
                addLog("! 警告: 未识别到文字");
            } else {
                setTopic(prev => {
                    const separator = prev.trim() ? '\n\n' : '';
                    return prev + separator + extractedText.trim();
                });
                addLog("图像文字提取成功");
            }
        } catch (err: any) {
            console.error(err);
            addLog(`! 识别失败: ${err.message}`);
        } finally {
            setIsExtracting(false);
            if (fileInputRef.current) {
                fileInputRef.current.value = '';
            }
        }
    };

    const handleStyleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            addLog("! 错误: 仅支持图片文件作为参考");
            return;
        }

        try {
            const base64 = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => {
                    const result = reader.result as string;
                    resolve(result.split(',')[1]);
                };
                reader.onerror = reject;
                reader.readAsDataURL(file);
            });

            setStyleImage({
                data: base64,
                mimeType: file.type
            });
            addLog("视觉风格参考已加载");
        } catch (err: any) {
            console.error(err);
            addLog(`! 参考图加载失败: ${err.message}`);
        } finally {
            if (styleInputRef.current) {
                styleInputRef.current.value = '';
            }
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    const triggerStyleInput = () => {
        styleInputRef.current?.click();
    };

    return (
        <div className="min-h-screen p-3 md:p-8 lg:p-12 flex items-center justify-center">
            {/* 
               Responsive Grid Strategy:
               Mobile: grid-cols-3. 
                 - Main Card: col-span-3 (Full width)
                 - Modes: col-span-1 (3 items fit in one row 1-1-1)
                 - HUD: col-span-3 (Full width)
                 - Result: col-span-3 (Full width)
               Desktop: grid-cols-6.
                 - Main Card: col-span-3, row-span-2
                 - Modes: col-span-1
            */}
            <div className="w-full max-w-[1200px] h-full grid grid-cols-3 md:grid-cols-6 md:grid-rows-[auto_auto_auto] gap-4 md:gap-6 auto-rows-auto md:auto-rows-fr">

                {/* --- GRID AREA A: CORE INTELLIGENCE (MAIN CARD) --- */}
                {/* Mobile: Full width, Desktop: Half width, 2 rows */}
                <GlassCard className="col-span-3 md:col-span-3 md:row-span-2 flex flex-col p-5 md:p-10 relative min-h-[400px] md:min-h-0" intensity="lg">
                    {/* Background Graphic */}
                    <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none transform translate-x-10 -translate-y-10">
                        <i className="fa-solid fa-brain text-[8rem] md:text-[12rem] text-apple-blue"></i>
                    </div>

                    {/* Style Reference Button (Top Right) */}
                    <div className="absolute top-4 right-4 md:top-6 md:right-6 z-20">
                        <input
                            type="file"
                            ref={styleInputRef}
                            className="hidden"
                            accept="image/*"
                            onChange={handleStyleImageUpload}
                        />
                        <button
                            onClick={triggerStyleInput}
                            disabled={engineState.status === 'PROCESSING'}
                            className={`flex items-center gap-2 px-2.5 py-2 md:px-3 md:py-2 rounded-full backdrop-blur-md transition-all duration-300 shadow-sm border ${
                                styleImage 
                                ? 'bg-apple-blue/10 border-apple-blue/30 text-apple-blue hover:bg-apple-blue/20' 
                                : 'bg-white/40 border-white/60 text-apple-gray hover:bg-white/60 hover:text-apple-blue'
                            } ${engineState.status === 'PROCESSING' ? 'opacity-50 cursor-not-allowed' : ''}`}
                            title={styleImage ? "点击更换参考图" : "上传参考图以提取风格"}
                        >
                            {styleImage ? (
                                <>
                                    <CheckCircle2 size={16} />
                                    <span className="hidden md:inline text-xs font-bold">视觉参考已就绪</span>
                                    <span className="md:hidden text-xs font-bold">已就绪</span>
                                </>
                            ) : (
                                <>
                                    <ImagePlus size={16} />
                                    <span className="hidden md:inline text-xs font-medium">上传风格参考</span>
                                    <span className="md:hidden text-xs font-medium">参考图</span>
                                </>
                            )}
                        </button>
                    </div>

                    <div className="relative z-10 flex flex-col h-full mt-2 md:mt-4">
                        <div className="mb-4 md:mb-6">
                            <h1 className="text-2xl md:text-3xl lg:text-4xl font-extrabold tracking-tight text-apple-text mb-2 bg-clip-text text-transparent bg-gradient-to-r from-apple-text to-apple-gray font-sc">
                                认知极限系统
                            </h1>
                            <div className="flex items-center gap-2">
                                <span className="px-2 py-0.5 rounded-full bg-apple-blue/10 text-apple-blue text-[10px] font-bold tracking-wider border border-apple-blue/20">V3.0 测试版</span>
                                <span className="text-apple-gray text-xs md:text-sm font-medium">释放无限涌现力</span>
                            </div>
                        </div>

                        <div className="relative flex-1 w-full mb-4 md:mb-6 group/input min-h-[160px]">
                            <textarea
                                value={topic}
                                onChange={(e) => setTopic(e.target.value)}
                                placeholder="在此输入您希望突破的认知领域或具体目标..."
                                className="w-full h-full bg-black/5 border border-black/5 rounded-2xl p-4 pb-12 md:p-6 md:pb-14 text-apple-text placeholder-apple-gray/60 focus:outline-none focus:ring-2 focus:ring-apple-blue/30 focus:bg-white/40 transition-all resize-none text-base md:text-lg leading-relaxed shadow-[inset_0_2px_4px_rgba(0,0,0,0.06)]"
                                disabled={engineState.status === 'PROCESSING'}
                            />
                            <div className="absolute bottom-3 right-3 md:bottom-4 md:right-4 flex items-center gap-2">
                                <input
                                    type="file"
                                    ref={fileInputRef}
                                    className="hidden"
                                    accept="image/*"
                                    onChange={handleImageUpload}
                                />
                                <button
                                    onClick={triggerFileInput}
                                    disabled={isExtracting || engineState.status === 'PROCESSING'}
                                    className="flex items-center gap-2 px-2.5 py-1.5 rounded-lg bg-white/60 hover:bg-white/90 text-apple-gray hover:text-apple-blue border border-black/5 shadow-sm backdrop-blur-md transition-all text-xs font-medium disabled:opacity-50 disabled:cursor-not-allowed group-hover/input:bg-white/80"
                                    title="上传截图识别文字"
                                >
                                    {isExtracting ? (
                                        <Loader2 size={14} className="animate-spin" />
                                    ) : (
                                        <ImageIcon size={14} />
                                    )}
                                    <span className="hidden sm:inline">{isExtracting ? '识别中...' : '识别图片'}</span>
                                    <span className="sm:hidden">{isExtracting ? '...' : 'OCR'}</span>
                                </button>
                            </div>
                        </div>

                        <button 
                            onClick={handleActivate}
                            disabled={!topic.trim() || engineState.status === 'PROCESSING'}
                            className={`
                                group relative w-full py-3.5 md:py-4 rounded-xl font-bold tracking-wide transition-all duration-300 overflow-hidden shadow-lg
                                ${!topic.trim() || engineState.status === 'PROCESSING'
                                    ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                                    : 'bg-apple-text text-white hover:shadow-xl active:scale-[0.98]'
                                }
                            `}
                        >
                             <div className="absolute inset-0 bg-gradient-to-r from-apple-blue to-apple-purple opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
                             <div className="relative z-10 flex items-center justify-center gap-2">
                                {engineState.status === 'PROCESSING' ? (
                                    <span className="animate-pulse">正在运算...</span>
                                ) : (
                                    <>
                                        <Play size={18} fill="currentColor" />
                                        <span>激活认知引擎</span>
                                    </>
                                )}
                             </div>
                        </button>
                    </div>
                </GlassCard>

                {/* --- GRID AREA B: MODE - SINGULARITY --- */}
                {/* Mobile: 1 col (1/3 width), Desktop: 1 col */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.SINGULARITY)}
                    className={`col-span-1 md:col-span-1 md:row-span-1 p-3 md:p-5 flex flex-col justify-between min-h-[140px] md:min-h-[auto] ${mode === SystemMode.SINGULARITY ? 'ring-2 ring-apple-blue ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                    <div className="flex justify-between items-start mb-2 md:mb-0">
                         <div className={`p-2 md:p-2.5 rounded-2xl ${mode === SystemMode.SINGULARITY ? 'bg-apple-blue text-white shadow-lg shadow-apple-blue/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Hexagon size={16} className="md:w-5 md:h-5" />
                        </div>
                        {mode === SystemMode.SINGULARITY && <div className="w-1.5 h-1.5 rounded-full bg-apple-blue animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-sm md:text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].label}</h3>
                        <p className="text-[9px] md:text-[10px] text-apple-gray leading-tight line-clamp-3 md:line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA C: MODE - METAMORPHOSIS --- */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.METAMORPHOSIS)}
                    className={`col-span-1 md:col-span-1 md:row-span-1 p-3 md:p-5 flex flex-col justify-between min-h-[140px] md:min-h-[auto] ${mode === SystemMode.METAMORPHOSIS ? 'ring-2 ring-apple-purple ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start mb-2 md:mb-0">
                         <div className={`p-2 md:p-2.5 rounded-2xl ${mode === SystemMode.METAMORPHOSIS ? 'bg-apple-purple text-white shadow-lg shadow-apple-purple/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Layers size={16} className="md:w-5 md:h-5" />
                        </div>
                        {mode === SystemMode.METAMORPHOSIS && <div className="w-1.5 h-1.5 rounded-full bg-apple-purple animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-sm md:text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].label}</h3>
                        <p className="text-[9px] md:text-[10px] text-apple-gray leading-tight line-clamp-3 md:line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA D: MODE - ZENITH --- */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.ZENITH)}
                    className={`col-span-1 md:col-span-1 md:row-span-1 p-3 md:p-5 flex flex-col justify-between min-h-[140px] md:min-h-[auto] ${mode === SystemMode.ZENITH ? 'ring-2 ring-green-500 ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start mb-2 md:mb-0">
                         <div className={`p-2 md:p-2.5 rounded-2xl ${mode === SystemMode.ZENITH ? 'bg-green-500 text-white shadow-lg shadow-green-500/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Sparkles size={16} className="md:w-5 md:h-5" />
                        </div>
                        {mode === SystemMode.ZENITH && <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-sm md:text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.ZENITH].label}</h3>
                        <p className="text-[9px] md:text-[10px] text-apple-gray leading-tight line-clamp-3 md:line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.ZENITH].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA E: HUD --- */}
                {/* Mobile: Full width (3 cols), Desktop: 3 cols */}
                <div className="col-span-3 md:col-span-3 md:row-span-1">
                    <ProcessingHUD state={engineState} />
                </div>

                {/* --- GRID AREA F: OUTPUT --- */}
                {/* Mobile: Full width (3 cols), Desktop: Full width (6 cols) */}
                <div className="col-span-3 md:col-span-6 md:row-span-1 h-full min-h-[300px]">
                    <ResultView result={result} />
                </div>

            </div>
        </div>
    );
};

export default App;

import React from 'react';

interface GlassCardProps {
    children: React.ReactNode;
    className?: string;
    intensity?: 'sm' | 'md' | 'lg';
    interactive?: boolean;
    onClick?: () => void;
}

export const GlassCard: React.FC<GlassCardProps> = ({ 
    children, 
    className = '', 
    intensity = 'md',
    interactive = false,
    onClick
}) => {
    const baseStyles = "relative overflow-hidden transition-all duration-300 ease-[cubic-bezier(0.25,0.46,0.45,0.94)]";

    // Responsive radius: tighter on mobile, apple-style large on desktop
    const radius = "rounded-2xl md:rounded-[24px]";

    const intensityStyles = {
        sm: "bg-white/40 backdrop-blur-xl border border-white/50 shadow-glass-sm",
        md: "bg-white/50 backdrop-blur-2xl border border-white/60 shadow-glass-md",
        lg: "bg-white/60 backdrop-blur-3xl border border-white/70 shadow-glass-lg"
    };

    const interactiveStyles = interactive 
        ? "cursor-pointer hover:-translate-y-1 hover:scale-[1.01] hover:bg-white/70 active:scale-[0.98] hover:shadow-glass-xl" 
        : "";

    return (
        <div 
            className={`${baseStyles} ${radius} ${intensityStyles[intensity]} ${interactiveStyles} ${className} group`}
            onClick={onClick}
        >
            {/* Mirror Highlight */}
            <div className="absolute inset-0 bg-gradient-to-tr from-white/0 via-white/40 to-white/0 opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none" />

            {/* Inner Highlight (Top Border) */}
            <div className="absolute inset-x-0 top-0 h-px bg-white/80 opacity-50" />

            {children}
        </div>
    );
};

